/**
 * Connect to a DevtoolsService server over WebSocket.
 * @param url - WebSocket URL (e.g., "ws://localhost:9000")
 * @returns A connected DevtoolsServiceClient instance
 */
export async function connectDevtoolsService(
  url: string,
  options: ConnectLaneOptions = {},
): Promise<DevtoolsServiceClient> {
  return connectLane(wsConnector(url), DevtoolsServiceClient, {
    ...options,
    laneMetadata: options.laneMetadata ?? voxServiceMetadata("DevtoolsService"),
  });
}

// Handler interface for DevtoolsService
